# %% ../nbs/8_wandb_writer.ipynb #818c61c8
def extract_log_cfg(cfg):
    log_cfg = OmegaConf.create({})
    log_cfg.algorithm = cfg.algorithm.name

    log_cfg.num_clients = cfg.num_clients
    log_cfg.m = cfg.m
    log_cfg.n_rounds = cfg.n_rounds
    log_cfg.local_epochs = cfg.local_epochs
    log_cfg.random_seed = cfg.random_seed
    log_cfg.batch_size = cfg.batch_size
    log_cfg.now = cfg.now


    log_cfg.data = cfg.data.name
    log_cfg.partitioner = cfg.partitioner

    log_cfg.model = cfg.model.name
    log_cfg.hidden_dim = cfg.model.hidden_dim if hasattr(cfg.model, 'hidden_dim') else 512



    log_cfg.optimizer = cfg.optimizer.cls
    log_cfg.lr = cfg.optimizer.lr
    kwargs = get_clean_kwargs(cfg.optimizer)
    kwargs.pop('cls', None)
    kwargs.pop('lr', None)
    for key in kwargs.keys():
        log_cfg[key] = kwargs[key]
        
    kwargs = get_clean_kwargs(cfg.algorithm)
    kwargs.pop('name', None)
    for key in kwargs.keys():
        log_cfg[key] = kwargs[key]

    log_cfg.project_name = cfg.project_name
    return log_cfg

# %% ../nbs/8_wandb_writer.ipynb #8ada7fd7
class WandbWriter:

    def __init__(self, cfg):
        self.server = cfg.server
        self.cfg = extract_log_cfg(cfg)
        self.cfg = argparse.Namespace(**self.cfg)
        print(self.cfg.algorithm)
        self.exp_name = self.cfg.algorithm
        self.wandb_log_dir = os.path.join(self.server.logs_dir, cfg.project_name, cfg.algorithm.name , str(self.cfg.random_seed))
        if not os.path.exists(self.wandb_log_dir):
            os.makedirs(self.wandb_log_dir, exist_ok=True)

        key = os.getenv("WANDB_API_KEY")
        wandb.login(key=key, verify=False)
        self.run = wandb.init(project=self.cfg.project_name,
                              name= self.exp_name,
                              config=self.cfg,
                              dir= self.wandb_log_dir)

# %% ../nbs/8_wandb_writer.ipynb #26127248
@patch
def write(self: WandbWriter, lst_active_ids, lst_train_res, lst_test_res, round):

    # Training results (for participating clients)
    local_train_losses = [r["loss"] for r in lst_train_res] if lst_train_res else []
    local_train_metrics = [r["metrics"] for r in lst_train_res] if lst_train_res else []

    # lst_train_histories = [{"client_id": client_id, "loss": loss, **metrics} 
    #                        for client_id, loss, metrics in zip(range(len(lst_test_res)), local_train_losses, local_train_metrics)]
    lst_train_histories = [
        {"round": round, "client_id": client_id, "loss": loss, **metrics}
        for client_id, loss, metrics in zip(lst_active_ids, local_train_losses, local_train_metrics)
    ]
    train_table = wandb.Table(dataframe=pd.DataFrame(lst_train_histories))

    # Test results (for all clients)
    local_test_losses = [r["loss"] for r in lst_test_res] if lst_test_res else []
    local_test_metrics = [r["metrics"] for r in lst_test_res] if lst_test_res else []

    lst_test_histories = [
        {"round": round, "client_id": client_id, "loss": loss, **metrics}
        for client_id, loss, metrics in zip(lst_active_ids, local_test_losses, local_test_metrics)
    ]
    test_table = wandb.Table(dataframe=pd.DataFrame(lst_test_histories))

    # Compute averages safely
    avg_train_losses = np.mean(local_train_losses) if local_train_losses else 0.0
    avg_train_metrics = self.avg_lst_dicts(local_train_metrics) if local_train_metrics else {}

    avg_test_losses = np.mean(local_test_losses) if local_test_losses else 0.0
    avg_test_metrics = self.avg_lst_dicts(local_test_metrics) if local_test_metrics else {}

    # Prepare logs
    train_metrics = {f"train_{k}": v for k, v in avg_train_metrics.items()}
    test_metrics = {f"test_{k}": v for k, v in avg_test_metrics.items()}

    to_log = {"train_loss": avg_train_losses,
              **train_metrics,
              "test_loss": avg_test_losses,
              **test_metrics,
              f"Round {round} Train metrics": train_table,
              f"Round {round} Test metrics": test_table}

    self.run.log(to_log)
    return pd.DataFrame(lst_train_histories), pd.DataFrame(lst_test_histories)


# %% ../nbs/8_wandb_writer.ipynb #9c8f1b46
@patch
def avg_lst_dicts(self: WandbWriter, lst_dict):
    return {key: sum(d[key] for d in lst_dict) / len(lst_dict) for key in lst_dict[0]}

# %% ../nbs/8_wandb_writer.ipynb #2789d536
@patch
def save(self: WandbWriter, res):
    # train_df = pd.concat([pd.DataFrame(d0) for d0 in res[0]])
    # test_df = pd.concat([pd.DataFrame(d1) for d1 in res[1]])

    train_df = pd.concat([r[0] for r in res], ignore_index=True)
    test_df = pd.concat([r[1] for r in res], ignore_index=True)

    os.makedirs(self.server.res_dir, exist_ok=True)
    test_df.to_csv(f"{self.server.res_dir}/test.csv", index=False)
    train_df.to_csv(f"{self.server.res_dir}/train.csv", index=False)

# %% ../nbs/8_wandb_writer.ipynb #70f92f1a
@patch
def finish(self: WandbWriter):
    self.run.finish()
